// Import necessary packages for testing\\nimport org.junit.jupiter.api.Test;\\nimport org.springframework.beans.factory.annotation.Autowired;\\nimport org.springframework.boot.test.context.SpringBootTest;\\nimport org.springframework.test.web.reactive.WebTestClient;\\nimport static org.assertj.core.api.Assertions.assertThat;\\n\\n@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)\\npublic class OrchestratorWebClientAdapterTest {\\n\\n    @Autowired\\n    private WebTestClient webTestClient;\\n\\n    @Test\\n    public void testSomeWebClientFunctionality() {\\n        // Example test case\\n        String response = webTestClient.get()\\n                .uri("/api/example")\\n                .exchange()\\n                .expectStatus().isOk()\\n                .returnResult(String.class)\\n                .getResponseBody()\\n                .blockFirst();\\n\\n        assertThat(response).isEqualTo("Expected Response");\\n    }\\n}